source.buildSpec:
{
  "version": "0.2",
  "phases": {
    "install": {
      "runtime-versions": {
        "nodejs": "18"
      },
      "commands": [
        "echo Installing dependencies...",
        "npm ci"
      ]
    },
    "build": {
      "commands": [
        "echo Build started on `date`",
        "npm run build",
        "npx cdk synth"
      ]
    },
    "post_build": {
      "commands": [
        "echo Deploying CDK stacks...",
        "npx cdk deploy WorkflowStack --require-approval never"
      ]
    }
  },
  "artifacts": {
    "base-directory": "cdk.out",
    "files": [
      "**/*"
    ]
  }
}
